				num /= 60;
				min = (int)(num % 60);
				num /= 60;
				hr = (int)(num % 24);
				num /= 24;
				day = (int)(num % 31) + 1;
				num /= 31;
				mnth = (int)(num % 12) + 1;
				num /= 12;
				yr = (int)(num - 9999);
