						fixed (byte* ptr4 = uriEscapingBuffer)
						{
							byte* ptr5 = ptr4;
							byte* pDst = ptr5;
							XmlUtf8RawTextWriter.CharToUTF8(ref pSrc, pSrcEnd, ref pDst);
