				}
				RawText("<?xml version=\"");
				RawText("1.0");
				if (encoding != null)
				{
					RawText("\" encoding=\"");
					RawText(encoding.WebName);
				}
				if (standalone != XmlStandalone.Omit)
				{
					RawText("\" standalone=\"");
					RawText((standalone == XmlStandalone.Yes) ? "yes" : "no");
