				this.s1 = s1;
				this.s2 = s2;
				this.s3 = s3;
			}

			public void InitEvent(XmlEventType eventType, string s1, string s2, string s3, object o)
			{
				this.eventType = eventType;
				this.s1 = s1;
				this.s2 = s2;
				this.s3 = s3;
				this.o = o;
