			}
			XmlReader xmlReader = new XmlTextReaderImpl(input, null, 0, this, baseUri, baseUriString, inputContext, closeInput);
			if (ValidationType != ValidationType.None)
			{
				xmlReader = AddValidation(xmlReader);
