			}
			nameTable = xmlNameTable;
			if (namespaceManager == null)
			{
				namespaceManager = new XmlNamespaceManager(xmlNameTable);
			}
			xmlContext.xmlSpace = context.XmlSpace;
			xmlContext.xmlLang = context.XmlLang;
		}

