			{
				ThrowUnexpectedToken((!rootElementParsed && dtdInfo == null) ? "DOCTYPE" : "<!--");
			}
			if (!xmlCharType.IsWhiteSpace(ps.chars[ps.charPos + 7]))
			{
				ThrowExpectingWhitespace(ps.charPos + 7);
			}
			if (dtdInfo != null)
			{
