			}
			if (rootElementParsed)
			{
				Throw(ps.charPos - 2, "DTD must be defined before the document root element.");
			}
			ps.charPos += 8;
			await EatWhitespacesAsync(null).ConfigureAwait(continueOnCapturedContext: false);
