		public override void Close()
		{
			try
			{
				FlushBuffer();
				FlushEncoder();
			}
			finally
			{
				writeToNull = true;
				if (stream != null)
				{
					try
					{
						stream.Flush();
					}
					finally
					{
						try
						{
							if (closeOutput)
							{
								stream.Close();
							}
						}
						finally
						{
							stream = null;
						}
					}
				}
			}
		}

		public override void Flush()
		{
			FlushBuffer();
			FlushEncoder();
			if (stream != null)
			{
				stream.Flush();
			}
		}

		protected virtual void FlushBuffer()
		{
			try
			{
				if (!writeToNull)
				{
					stream.Write(bufBytes, 1, bufPos - 1);
