			}
			catch
			{
				writeToNull = true;
				throw;
			}
			finally
			{
				bufBytes[0] = bufBytes[bufPos - 1];
				if (IsSurrogateByte(bufBytes[0]))
				{
					bufBytes[1] = bufBytes[bufPos];
					bufBytes[2] = bufBytes[bufPos + 1];
					bufBytes[3] = bufBytes[bufPos + 2];
				}
				textPos = ((textPos == bufPos) ? 1 : 0);
				attrEndPos = ((attrEndPos == bufPos) ? 1 : 0);
				contentPos = 0;
				cdataPos = 0;
				bufPos = 1;
			}
		}

