			object[] args;
			while (true)
			{
				if (num >= chars.Length)
				{
					return;
				}
				if (!xmlCharType.IsTextChar(chars[num]))
				{
					switch (chars[num])
					{
					case '&':
					case '<':
					case ']':
						args = XmlException.BuildCharExceptionArgs(chars, num);
						text = Res.GetString("'{0}', hexadecimal value {1}, is an invalid character.", args);
						break;
