		public NewLineHandling NewLineHandling => newLineHandling;

		public string NewLineChars => newLineChars;

		public bool Indent
		{
			get
			{
				return indent == TriState.True;
			}
			set
			{
				CheckReadOnly("Indent");
				indent = (value ? TriState.True : TriState.False);
			}
		}

		public string IndentChars
		{
			get
			{
				return indentChars;
			}
			set
			{
				CheckReadOnly("IndentChars");
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				indentChars = value;
			}
		}

		public bool NewLineOnAttributes => newLineOnAttributes;

		public bool CloseOutput
		{
			get
