			}
			set
			{
				CheckReadOnly("ConformanceLevel");
				if ((uint)value > 2u)
				{
					throw new ArgumentOutOfRangeException("value");
				}
				conformanceLevel = value;
			}
		}

		public bool CheckCharacters => checkCharacters;

		public NamespaceHandling NamespaceHandling
		{
