		public override bool ReadAttributeValue()
		{
			if (cachedNode.NodeType != XmlNodeType.Attribute)
			{
				return false;
			}
			cachedNode = CreateDummyTextNode(cachedNode.RawValue, cachedNode.Depth + 1);
			return true;
		}

