			switch (eref.Name)
			{
			case "lt":
				eref.AppendChildForLoad(doc.CreateTextNode("<"), doc);
				doc.IsLoading = isLoading;
				return;
			case "gt":
				eref.AppendChildForLoad(doc.CreateTextNode(">"), doc);
				doc.IsLoading = isLoading;
				return;
			case "amp":
				eref.AppendChildForLoad(doc.CreateTextNode("&"), doc);
				doc.IsLoading = isLoading;
				return;
			case "apos":
				eref.AppendChildForLoad(doc.CreateTextNode("'"), doc);
				doc.IsLoading = isLoading;
				return;
			case "quot":
				eref.AppendChildForLoad(doc.CreateTextNode("\""), doc);
				doc.IsLoading = isLoading;
				return;
