		internal static void SplitName(string name, out string prefix, out string localName)
		{
			int num = name.IndexOf(':');
			if (-1 == num || num == 0 || name.Length - 1 == num)
			{
				prefix = string.Empty;
				localName = name;
			}
			else
			{
				prefix = name.Substring(0, num);
				localName = name.Substring(num + 1);
			}
		}

