					}
					else
					{
						ThrowUnexpectedToken(curPos, "\"", "'");
					}
				}
				else if (await GetTokenAsync(needWhiteSpace: false).ConfigureAwait(continueOnCapturedContext: false) == Token.Literal)
				{
