				{
					return charCount;
				}
				int num = bytes[byteIndex++];
				byteCount--;
				chars[charIndex++] = (bigEndian ? ((char)((lastByte << 8) | num)) : ((char)((num << 8) | lastByte)));
				lastByte = -1;
			}
