			if (bigEndian == BitConverter.IsLittleEndian)
			{
				int num2 = byteIndex;
				int num3 = num2 + (byteCount & -2);
				if (bigEndian)
				{
					while (num2 < num3)
					{
						int num4 = bytes[num2++];
						int num5 = bytes[num2++];
						chars[charIndex++] = (char)((num4 << 8) | num5);
					}
				}
				else
				{
					while (num2 < num3)
					{
						int num6 = bytes[num2++];
						int num7 = bytes[num2++];
						chars[charIndex++] = (char)((num7 << 8) | num6);
