					string text2 = linePosition.ToString(CultureInfo.InvariantCulture);
					object[] array = args;
					result = Res.GetString(res, array);
					array = new string[3] { result, text, text2 };
					result = Res.GetString("{0} Line {1}, position {2}.", array);
