		internal static string ToXmlString(TypeData type, object value)
		{
			if (value == null)
			{
				return null;
			}
			switch (type.XmlType)
			{
			case "boolean":
				return XmlConvert.ToString((bool)value);
			case "unsignedByte":
				return XmlConvert.ToString((byte)value);
			case "char":
				return XmlConvert.ToString((int)(char)value);
			case "dateTime":
				return XmlConvert.ToString((DateTime)value, XmlDateTimeSerializationMode.RoundtripKind);
			case "date":
				return ((DateTime)value).ToString("yyyy-MM-dd", CultureInfo.InvariantCulture);
			case "time":
				return ((DateTime)value).ToString("HH:mm:ss.FFFFFFF", CultureInfo.InvariantCulture);
			case "decimal":
				return XmlConvert.ToString((decimal)value);
			case "double":
				return XmlConvert.ToString((double)value);
			case "short":
				return XmlConvert.ToString((short)value);
			case "int":
				return XmlConvert.ToString((int)value);
			case "long":
				return XmlConvert.ToString((long)value);
			case "byte":
				return XmlConvert.ToString((sbyte)value);
			case "float":
				return XmlConvert.ToString((float)value);
			case "unsignedShort":
				return XmlConvert.ToString((ushort)value);
			case "unsignedInt":
				return XmlConvert.ToString((uint)value);
			case "unsignedLong":
				return XmlConvert.ToString((ulong)value);
			case "guid":
				return XmlConvert.ToString((Guid)value);
			case "base64":
			case "base64Binary":
				if (value != null)
				{
					return Convert.ToBase64String((byte[])value);
				}
				return string.Empty;
			case "hexBinary":
				if (value != null)
				{
					return XmlConvert.ToBinHexString((byte[])value);
				}
				return string.Empty;
			case "duration":
				return (string)value;
			default:
				if (!(value is IFormattable))
				{
					return value.ToString();
				}
				return ((IFormattable)value).ToString(null, CultureInfo.InvariantCulture);
			}
		}

		internal static object FromXmlString(TypeData type, string value)
		{
			if (value == null)
			{
				return null;
			}
			switch (type.XmlType)
			{
			case "boolean":
				return XmlConvert.ToBoolean(value);
			case "unsignedByte":
				return XmlConvert.ToByte(value);
			case "char":
				return (char)XmlConvert.ToInt32(value);
			case "dateTime":
				return XmlConvert.ToDateTime(value, XmlDateTimeSerializationMode.RoundtripKind);
			case "date":
				return XmlConvert.ToDateTime(value).Date;
			case "time":
				return DateTime.ParseExact(value, allTimeFormats, DateTimeFormatInfo.InvariantInfo, DateTimeStyles.AllowLeadingWhite | DateTimeStyles.AllowTrailingWhite | DateTimeStyles.NoCurrentDateDefault | DateTimeStyles.RoundtripKind);
			case "decimal":
				return XmlConvert.ToDecimal(value);
			case "double":
				return XmlConvert.ToDouble(value);
			case "short":
				return XmlConvert.ToInt16(value);
			case "int":
				return XmlConvert.ToInt32(value);
			case "long":
				return XmlConvert.ToInt64(value);
			case "byte":
				return XmlConvert.ToSByte(value);
			case "float":
				return XmlConvert.ToSingle(value);
			case "unsignedShort":
				return XmlConvert.ToUInt16(value);
			case "unsignedInt":
				return XmlConvert.ToUInt32(value);
			case "unsignedLong":
				return XmlConvert.ToUInt64(value);
			case "guid":
				return XmlConvert.ToGuid(value);
			case "base64":
			case "base64Binary":
				return Convert.FromBase64String(value);
			case "hexBinary":
				return XmlConvert.FromBinHexString(value);
			case "duration":
				return value;
			default:
				if (type.Type != null)
				{
					return Convert.ChangeType(value, type.Type, null);
				}
				return value;
			}
		}
	}
