			}
			object obj = wildcards[wildcard];
			if (obj == null)
			{
				wildcards.Add(wildcard, last);
				particles.Add(particle);
				last++;
			}
			else if (particle != null)
			{
				particles[(int)obj] = particle;
			}
		}

		public ICollection GetNamespaceListSymbols(NamespaceList list)
