	internal class NamespaceListNode : SyntaxTreeNode
	{
		protected NamespaceList namespaceList;

		protected object particle;

		public override bool IsNullable
		{
			get
			{
				throw new InvalidOperationException();
			}
		}

		public NamespaceListNode(NamespaceList namespaceList, object particle)
		{
			this.namespaceList = namespaceList;
			this.particle = particle;
		}

		public virtual ICollection GetResolvedSymbols(SymbolsDictionary symbols)
		{
			return symbols.GetNamespaceListSymbols(namespaceList);
		}

		public override void ExpandTree(InteriorNode parent, SymbolsDictionary symbols, Positions positions)
		{
			SyntaxTreeNode syntaxTreeNode = null;
			foreach (int resolvedSymbol in GetResolvedSymbols(symbols))
			{
				if (symbols.GetParticle(resolvedSymbol) != particle)
				{
					symbols.IsUpaEnforced = false;
				}
				LeafNode leafNode = new LeafNode(positions.Add(resolvedSymbol, particle));
				syntaxTreeNode = ((syntaxTreeNode != null) ? ((SyntaxTreeNode)new ChoiceNode
				{
					LeftChild = syntaxTreeNode,
					RightChild = leafNode
				}) : ((SyntaxTreeNode)leafNode));
			}
			if (parent.LeftChild == this)
			{
				parent.LeftChild = syntaxTreeNode;
			}
			else
			{
				parent.RightChild = syntaxTreeNode;
			}
		}

		public override void ConstructPos(BitSet firstpos, BitSet lastpos, BitSet[] followpos)
		{
			throw new InvalidOperationException();
		}
	}
	internal abstract class InteriorNode : SyntaxTreeNode
	{
		private SyntaxTreeNode leftChild;

		private SyntaxTreeNode rightChild;

		public SyntaxTreeNode LeftChild
		{
			get
			{
				return leftChild;
			}
			set
			{
				leftChild = value;
			}
		}

		public SyntaxTreeNode RightChild
		{
			get
			{
				return rightChild;
			}
			set
			{
				rightChild = value;
			}
		}

		protected void ExpandTreeNoRecursive(InteriorNode parent, SymbolsDictionary symbols, Positions positions)
		{
			Stack<InteriorNode> stack = new Stack<InteriorNode>();
			InteriorNode interiorNode = this;
			while (interiorNode.leftChild is ChoiceNode || interiorNode.leftChild is SequenceNode)
			{
				stack.Push(interiorNode);
				interiorNode = (InteriorNode)interiorNode.leftChild;
			}
			interiorNode.leftChild.ExpandTree(interiorNode, symbols, positions);
			while (true)
			{
				if (interiorNode.rightChild != null)
				{
					interiorNode.rightChild.ExpandTree(interiorNode, symbols, positions);
				}
				if (stack.Count != 0)
				{
					interiorNode = stack.Pop();
					continue;
				}
				break;
			}
		}

		public override void ExpandTree(InteriorNode parent, SymbolsDictionary symbols, Positions positions)
		{
			leftChild.ExpandTree(this, symbols, positions);
			if (rightChild != null)
			{
				rightChild.ExpandTree(this, symbols, positions);
			}
		}
	}
	internal sealed class SequenceNode : InteriorNode
	{
		private struct SequenceConstructPosContext(SequenceNode node, BitSet firstpos, BitSet lastpos)
		{
			public SequenceNode this_ = node;

			public BitSet firstpos = firstpos;

			public BitSet lastpos = lastpos;

			public BitSet lastposLeft = null;

			public BitSet firstposRight = null;
		}

		public override bool IsNullable
		{
			get
			{
				SequenceNode sequenceNode = this;
				SyntaxTreeNode syntaxTreeNode;
				do
				{
					if (sequenceNode.RightChild.IsRangeNode && ((LeafRangeNode)sequenceNode.RightChild).Min == 0m)
					{
						return true;
					}
					if (!sequenceNode.RightChild.IsNullable && !sequenceNode.RightChild.IsRangeNode)
					{
						return false;
					}
					syntaxTreeNode = sequenceNode.LeftChild;
					sequenceNode = syntaxTreeNode as SequenceNode;
				}
				while (sequenceNode != null);
				return syntaxTreeNode.IsNullable;
			}
		}

		public override void ConstructPos(BitSet firstpos, BitSet lastpos, BitSet[] followpos)
		{
			Stack<SequenceConstructPosContext> stack = new Stack<SequenceConstructPosContext>();
			SequenceConstructPosContext item = new SequenceConstructPosContext(this, firstpos, lastpos);
			SequenceNode this_;
			while (true)
			{
				this_ = item.this_;
				item.lastposLeft = new BitSet(lastpos.Count);
				if (!(this_.LeftChild is SequenceNode))
				{
					break;
				}
				stack.Push(item);
				item = new SequenceConstructPosContext((SequenceNode)this_.LeftChild, item.firstpos, item.lastposLeft);
			}
			this_.LeftChild.ConstructPos(item.firstpos, item.lastposLeft, followpos);
			while (true)
			{
				item.firstposRight = new BitSet(firstpos.Count);
				this_.RightChild.ConstructPos(item.firstposRight, item.lastpos, followpos);
				if (this_.LeftChild.IsNullable && !this_.RightChild.IsRangeNode)
				{
					item.firstpos.Or(item.firstposRight);
				}
				if (this_.RightChild.IsNullable)
				{
					item.lastpos.Or(item.lastposLeft);
				}
				for (int num = item.lastposLeft.NextSet(-1); num != -1; num = item.lastposLeft.NextSet(num))
				{
					followpos[num].Or(item.firstposRight);
				}
				if (this_.RightChild.IsRangeNode)
				{
					((LeafRangeNode)this_.RightChild).NextIteration = item.firstpos.Clone();
				}
				if (stack.Count != 0)
				{
					item = stack.Pop();
					this_ = item.this_;
					continue;
				}
				break;
			}
		}

		public override void ExpandTree(InteriorNode parent, SymbolsDictionary symbols, Positions positions)
		{
			ExpandTreeNoRecursive(parent, symbols, positions);
		}
	}
	internal sealed class ChoiceNode : InteriorNode
	{
		public override bool IsNullable
		{
			get
			{
				ChoiceNode choiceNode = this;
				SyntaxTreeNode syntaxTreeNode;
				do
				{
					if (choiceNode.RightChild.IsNullable)
					{
						return true;
					}
					syntaxTreeNode = choiceNode.LeftChild;
					choiceNode = syntaxTreeNode as ChoiceNode;
				}
				while (choiceNode != null);
				return syntaxTreeNode.IsNullable;
			}
		}

		private static void ConstructChildPos(SyntaxTreeNode child, BitSet firstpos, BitSet lastpos, BitSet[] followpos)
		{
			BitSet bitSet = new BitSet(firstpos.Count);
			BitSet bitSet2 = new BitSet(lastpos.Count);
			child.ConstructPos(bitSet, bitSet2, followpos);
			firstpos.Or(bitSet);
			lastpos.Or(bitSet2);
		}

		public override void ConstructPos(BitSet firstpos, BitSet lastpos, BitSet[] followpos)
		{
			BitSet bitSet = new BitSet(firstpos.Count);
			BitSet bitSet2 = new BitSet(lastpos.Count);
			ChoiceNode choiceNode = this;
			SyntaxTreeNode syntaxTreeNode;
			do
			{
				ConstructChildPos(choiceNode.RightChild, bitSet, bitSet2, followpos);
				syntaxTreeNode = choiceNode.LeftChild;
				choiceNode = syntaxTreeNode as ChoiceNode;
			}
			while (choiceNode != null);
			syntaxTreeNode.ConstructPos(firstpos, lastpos, followpos);
			firstpos.Or(bitSet);
			lastpos.Or(bitSet2);
		}

		public override void ExpandTree(InteriorNode parent, SymbolsDictionary symbols, Positions positions)
		{
			ExpandTreeNoRecursive(parent, symbols, positions);
		}
	}
