				schemaLocations = new Hashtable();
				if (schema.BaseUri != null)
				{
					schemaLocations.Add(schema.BaseUri, schema.BaseUri);
				}
				LoadExternals(schema, xsc);
			}
			ValidateIdAttribute(schema);
			Preprocess(schema, targetNamespace, Compositor.Root);
