						if (xe.SchemaType != null)
						{
							xe.SetElementType(xe.SchemaType);
						}
						else if (!xe.SchemaTypeName.IsEmpty)
						{
							xe.SetElementType(GetAnySchemaType(xe.SchemaTypeName));
