			RParens = 41,
			LBracket = 91,
			RBracket = 93,
			Star = 42,
			Plus = 43,
			Minus = 45,
			Eq = 61,
			Lt = 60,
			Gt = 62,
			Bang = 33,
			Dollar = 36,
			Apos = 39,
			Quote = 34,
			Union = 124,
			Ne = 78,
			Le = 76,
			Ge = 71,
			And = 65,
			Or = 79,
			DotDot = 68,
			SlashSlash = 83,
			Name = 110,
			String = 115,
			Number = 100,
			Axe = 97,
			Eof = 69
